const incoming = $input.first().json ?? {};
const body = incoming.body ?? incoming ?? {};

const clean = (value) => String(value ?? '').replace(/\s+/g, ' ').trim();
const toArray = (value) => {
  if (Array.isArray(value)) return value.map((item) => String(item ?? '').trim()).filter(Boolean);
  if (typeof value === 'string') return value.split(/[\n,]/).map((item) => item.trim()).filter(Boolean);
  return [];
};

const abRaw = body.authorBrief && typeof body.authorBrief === 'object' ? body.authorBrief : {};
const primaryProblemNote = clean(abRaw.primaryProblemNote ?? abRaw.primary_problem_note ?? '');
const primarySolutionNote = clean(abRaw.primarySolutionNote ?? abRaw.primary_solution_note ?? '');
const authorEvidenceNotes = Array.isArray(abRaw.evidenceNotes)
  ? abRaw.evidenceNotes.map((item) => String(item ?? '').trim()).filter(Boolean)
  : toArray(abRaw.evidence_notes ?? abRaw.evidenceNotes);

const slideSeed = Array.isArray(body.cardNews?.slides) ? body.cardNews.slides : [];
const normalizedSlides = slideSeed
  .map((item, index) => ({
    slide: Number(item?.slide ?? index + 1),
    role: clean(item?.role ?? item?.key ?? `slide_${index + 1}`),
    title: clean(item?.title),
    text: clean(item?.text ?? item?.body),
  }))
  .filter((item) => item.text);

let evidencePoints = toArray(body.evidencePoints ?? body.evidence_points);
if (evidencePoints.length === 0 && authorEvidenceNotes.length > 0) {
  evidencePoints = authorEvidenceNotes;
}

const displayName = clean(body.displayName ?? body.display_name ?? body.titleHint ?? body.externalLabel ?? body.external_label ?? body.siteName ?? body.site_name) || '시공 사례';
const hook = clean(body.hook ?? body.headlineHook ?? body.headline_hook);
let problemSummary = clean(body.problemSummary ?? body.problem_summary);
let problemDetail = clean(body.problemDetail ?? body.problem_detail);
let solutionSummary = clean(body.solutionSummary ?? body.solution_summary);
let solutionDetail = clean(body.solutionDetail ?? body.solution_detail);
if (!problemDetail && primaryProblemNote) problemDetail = primaryProblemNote;
if (!solutionDetail && primarySolutionNote) solutionDetail = primarySolutionNote;

const blogDraftMarkdown = String(body.blogDraftMarkdown ?? body.blog_draft_markdown ?? '').trim();
const channel = clean(body.channel).toLowerCase() || 'cardnews';

const normalizeImageCtxRow = (item) => {
  if (!item || typeof item !== 'object' || Array.isArray(item)) return null;
  const assetId = clean(item.assetId ?? item.asset_id ?? item.id);
  const summaryLineRaw = clean(item.summaryLine ?? item.summary_line);
  const baRaw = clean(item.beforeAfter ?? item.before_after).toLowerCase();
  const beforeAfter = baRaw === 'before' ? 'before' : baRaw === 'after' ? 'after' : null;
  const productName = clean(item.productName ?? item.product_name) || null;
  const colorName = clean(item.colorName ?? item.color_name) || null;
  const location = clean(item.location) || null;
  const businessType = clean(item.businessType ?? item.business_type) || null;
  const bits = [
    Boolean(item.isMain ?? item.is_main) ? '대표컷' : '',
    beforeAfter === 'before' ? '비포' : beforeAfter === 'after' ? '애프터' : '',
    productName,
    colorName,
    location,
    businessType,
  ].filter(Boolean);
  const summaryLine = summaryLineRaw || bits.join(' · ') || null;
  const url = clean(item.url ?? item.preview_url ?? item.image_url ?? item.imageUrl);
  if (!assetId && !summaryLine) return null;
  return {
    assetId,
    url,
    beforeAfter,
    productName,
    colorName,
    location,
    businessType,
    isMain: Boolean(item.isMain ?? item.is_main),
    summaryLine: summaryLine || '현장 컷',
  };
};
const icRaw = body.imageContext ?? body.image_context ?? body.siteImageMetadata ?? body.site_image_metadata;
const imageContext = Array.isArray(icRaw)
  ? icRaw.map(normalizeImageCtxRow).filter(Boolean)
  : [];

const cardNewsSeed = normalizedSlides.length > 0
  ? normalizedSlides
  : [
      { slide: 1, role: 'hook', title: displayName, text: hook || '이 공간은 무엇이 달라졌을까요?' },
      { slide: 2, role: 'problem', title: '문제 인식', text: [problemSummary, problemDetail].filter(Boolean).join('\n\n') || '현장 과제를 정리 중입니다.' },
      { slide: 3, role: 'solution', title: '해결 접근', text: [solutionSummary, solutionDetail].filter(Boolean).join('\n\n') || '적용 방향을 정리 중입니다.' },
      { slide: 4, role: 'evidence', title: '변화 포인트', text: evidencePoints.length ? evidencePoints.map((item) => `- ${item}`).join('\n') : '전후 변화와 관찰 포인트를 정리 중입니다.' },
      { slide: 5, role: 'cta', title: '온라인 쇼룸에서 더 보기', text: `${displayName} 사례처럼 우리 공간에 맞는 교육 환경 구성이 필요하다면 온라인 쇼룸에서 비슷한 사례를 더 비교해보세요.` },
    ];

const authorBrief = {
  primaryProblemNote: primaryProblemNote || problemDetail,
  primarySolutionNote: primarySolutionNote || solutionDetail,
  evidenceNotes: authorEvidenceNotes.length ? authorEvidenceNotes : evidencePoints,
};

return [{
  json: {
    requestSource: incoming.body ? 'webhook' : 'manual',
    contentType: clean(body.contentType ?? body.content_type) || 'showroom-case-content',
    channel,
    displayName,
    siteName: clean(body.siteName ?? body.site_name),
    externalLabel: clean(body.externalLabel ?? body.external_label) || null,
    industry: clean(body.industry) || null,
    titleHint: clean(body.titleHint ?? body.title_hint) || displayName,
    hook,
    problemSummary,
    problemDetail,
    solutionSummary,
    solutionDetail,
    evidencePoints,
    authorBrief,
    cardNewsSeed,
    blogDraftMarkdown,
    imageContext,
    cardNewsModel: clean(body.cardNewsModel ?? body.cardnews_model ?? body.model) || 'gpt-4.1',
    blogModel: clean(body.blogModel ?? body.blog_model ?? body.model) || 'gpt-4.1',
    generatedAt: new Date().toISOString(),
  },
}];

const data = $input.first().json;
const slidesText = Array.isArray(data.cardNewsSeed)
  ? data.cardNewsSeed.map((slide) => `${slide.slide}. [${slide.role}] ${slide.title ? `${slide.title} :: ` : ''}${slide.text}`).join('\n')
  : '';

const ab = data.authorBrief || {};
const briefLines = [];
if (ab.primaryProblemNote) briefLines.push(`· 핵심 문제/과제 (운영자 확정): ${ab.primaryProblemNote}`);
if (ab.primarySolutionNote) briefLines.push(`· 해결/접근 (운영자 확정): ${ab.primarySolutionNote}`);
if (Array.isArray(ab.evidenceNotes) && ab.evidenceNotes.length) {
  briefLines.push(`· 근거·변화 포인트: ${ab.evidenceNotes.join(' / ')}`);
}
const briefBlock = briefLines.length
  ? ['[운영자 브리프 — 사실·메시지의 1순위 원천. 시드/슬라이드와 충돌하면 반드시 브리프를 따른다.]', ...briefLines].join('\n')
  : '[운영자 브리프] 비어 있음 → 아래 카드뉴스 시드만으로 작성.';

const prompt = [
  '당신은 파인드가구 콘텐츠 에디터다.',
  '쇼룸은 오프라인 전시장이 아니라 홈페이지 안의 온라인 사례 쇼룸이다.',
  '아래 시드·브리프를 바탕으로 클릭형 카드뉴스 최종 초안을 JSON으로 정리하라.',
  '브리프에 없는 사실은 추측하지 말고 생략하거나 일반 표현만 쓴다.',
  '반드시 JSON만 반환한다.',
  '',
  `[공개명] ${data.displayName}`,
  `[업종] ${data.industry ?? '미기재'}`,
  '',
  briefBlock,
  '',
  '[카드뉴스 시드(앱에서 온 참고안·슬라이드 텍스트)]',
  slidesText,
  '',
  '[출력 스키마]',
  '{',
  '  "master": {',
  '    "cta": "string",',
  '    "slides": [',
  '      { "slide": 1, "role": "hook", "title": "string", "text": "string" }',
  '    ]',
  '  },',
  '  "instagram": {',
  '    "slides": [',
  '      { "slide": 1, "role": "hook", "title": "string", "text": "string" }',
  '    ],',
  '    "caption": "string"',
  '  },',
  '  "facebook": {',
  '    "slides": [',
  '      { "slide": 1, "role": "hook", "title": "string", "text": "string" }',
  '    ],',
  '    "caption": "string"',
  '  }',
  '}',
  '',
  '규칙:',
  '- slide는 1부터 시작',
  '- master.slides는 역할 순서를 지키면 좋다: hook → problem → specific-problem → solution → evidence → cta (앱 6장 레이아웃과 호환)',
  '- 가능하면 총 6장을 채운다. 부족하면 최소 5장 이상.',
  '- title은 짧게, text는 카드 안에 들어갈 정도로 간결하게',
  '- 운영자 브리프와 모순되는 사실·수치를 만들지 마라.',
  '- CTA는 클릭 버튼형이 아니라 온라인 쇼룸 유도형 문장으로 작성',
].join('\n');

return [{
  json: {
    ...data,
    cardNewsRequestBody: {
      model: data.cardNewsModel,
      temperature: 0.7,
      max_tokens: 2400,
      response_format: { type: 'json_object' },
      messages: [
        {
          role: 'user',
          content: prompt,
        },
      ],
    },
  },
}];

const normalized = $('입력 정규화').first().json;
const response = $input.first().json ?? {};
const stripCodeFences = (value) => typeof value === 'string' ? value.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim() : '';
const rawContent = stripCodeFences(response.choices?.[0]?.message?.content ?? '');

let parsed;
try {
  parsed = JSON.parse(rawContent);
} catch (error) {
  parsed = {
    master: {
      cta: `${normalized.displayName} 사례처럼 우리 공간에 맞는 구성을 온라인 쇼룸에서 더 비교해보세요.`,
      slides: normalized.cardNewsSeed.map((slide) => ({ slide: slide.slide, role: slide.role, title: slide.title, text: slide.text })),
    },
    instagram: {
      slides: normalized.cardNewsSeed.map((slide) => ({ slide: slide.slide, role: slide.role, title: slide.title, text: slide.text })),
      caption: `${normalized.displayName} 사례 핵심만 빠르게 정리했습니다.`,
    },
    facebook: {
      slides: normalized.cardNewsSeed.map((slide) => ({ slide: slide.slide, role: slide.role, title: slide.title, text: slide.text })),
      caption: `${normalized.displayName} 사례를 온라인 쇼룸 맥락으로 정리했습니다.`,
    },
  };
}

return [{
  json: {
    ok: true,
    contentType: normalized.contentType,
    channel: 'cardnews',
    displayName: normalized.displayName,
    generatedAt: new Date().toISOString(),
    payload: {
      request: {
        displayName: normalized.displayName,
        siteName: normalized.siteName,
        externalLabel: normalized.externalLabel,
        industry: normalized.industry,
      },
      cardNews: parsed,
      raw: rawContent || null,
    },
  },
}];

const data = $input.first().json;
const clean = (value) => String(value ?? '').replace(/\s+/g, ' ').trim();
const ab = data.authorBrief || {};
const briefLines = [];
if (ab.primaryProblemNote) briefLines.push(`· 핵심 문제/과제 (운영자 확정): ${ab.primaryProblemNote}`);
if (ab.primarySolutionNote) briefLines.push(`· 해결/접근 (운영자 확정): ${ab.primarySolutionNote}`);
if (Array.isArray(ab.evidenceNotes) && ab.evidenceNotes.length) {
  briefLines.push(`· 근거·변화 포인트: ${ab.evidenceNotes.join(' / ')}`);
}
const briefBlock = briefLines.length
  ? ['[운영자 브리프 — 사실·메시지의 1순위 원천. 다른 필드와 충돌하면 브리프를 따른다.]', ...briefLines].join('\n')
  : '';

const imageLines = Array.isArray(data.imageContext) && data.imageContext.length
  ? data.imageContext
      .map((row) => {
        if (!row || typeof row !== 'object') return '';
        const id = clean(row.assetId ?? row.asset_id ?? '');
        const url = clean(row.url ?? row.preview_url ?? row.imageUrl ?? row.image_url);
        const meta = clean(row.summaryLine ?? row.summary_line);
        if (!url) {
          return meta ? `· [${id || '자산'}] (URL 없음) 메타: ${meta}` : '';
        }
        return `· [${id || '자산'}] 본문 삽입용 URL(복사해 그대로 쓸 것): ${url} | 메타 힌트: ${meta || '없음'}`;
      })
      .filter(Boolean)
  : [];
const imageContextBlock = imageLines.length
  ? [
      '[현장 사진 목록 — 아래 URL만 본문에 사용 가능. 목록에 없는 이미지 URL을 만들거나 추측하지 않는다.]',
      '[이미지 마크다운] body_markdown 안에서 각 사진을 한 번씩 `![한글 alt 설명](위 URL과 완전히 동일한 문자열)` 형태로 넣는다. alt는 접근성·SEO용: 장면·제품·비포/애프를 한두 문장 분량의 자연스러운 한국어로 쓰고, 메타 한 줄을 그대로 복붙하지 않는다.]',
      '[배치 순서] 컷을 넣는 순서는 엄격하지 않다. “이전에는 이랬고, 적용 후에는 이렇게 바뀌었다”는 흐름만 읽히면 된다. 앞·뒤 서술과 자연스럽게 맞춰 적당히 끼워 넣는다.]',
      ...imageLines,
    ].join('\n')
  : '';

const prompt = [
  '당신은 파인드가구 블로그 에디터다.',
  '쇼룸은 홈페이지 안의 온라인 사례 쇼룸이다.',
  '아래 초안과 케이스 정보를 바탕으로 블로그 발행용 초안을 JSON으로 정리하라.',
  '브리프에 없는 사실은 추측하지 말고 생략하거나 완곡하게만 다룬다.',
  '반드시 JSON만 반환한다.',
  '',
  `[공개명] ${data.displayName}`,
  `[업종] ${data.industry ?? '미기재'}`,
  `[한 줄 훅] ${data.hook || '없음'}`,
  `[문제 요약] ${data.problemSummary || '없음'}`,
  `[문제 상세] ${data.problemDetail || '없음'}`,
  `[해결 요약] ${data.solutionSummary || '없음'}`,
  `[해결 상세] ${data.solutionDetail || '없음'}`,
  `[변화 포인트] ${data.evidencePoints.length ? data.evidencePoints.join(' / ') : '없음'}`,
  '',
  briefBlock,
  '',
  imageContextBlock,
  '',
  '[블로그 초안 시드]',
  data.blogDraftMarkdown || '없음',
  '',
  '[출력 스키마]',
  '{',
  '  "title": "string",',
  '  "summary": "string",',
  '  "body_markdown": "string",',
  '  "hashtags": ["#태그1", "#태그2"],',
  '  "review_note": "string"',
  '}',
  '',
  '규칙:',
  '- 블로그는 과장 없이 설명형으로 작성한다.',
  '- 첫 문단에서 핵심 답(AEO용 요지)을 먼저 제시한다.',
  '- 운영자 브리프와 모순되는 주장을 하지 않는다.',
  '- body_markdown 분량: 한글 기준 최소 약 1,800자 이상. 가능하면 2,400~3,200자 수준으로 서술한다. 단락은 12개 이상 권장(소제목 ## 사용 가능). 짧은 나열형만 반복하지 말고 사례 맥락·근거·비교를 풀어 쓴다.',
  '- 현장 사진 목록이 있으면: 각 URL을 body_markdown에 마크다운 이미지로 최소 한 번씩 포함한다(alt 필수). 순서는 자유지만 전·후 변화 서사와 맞출 것. 메타 라벨을 그대로 나열하지 말고 문장·alt에 녹인다.',
  '- 브리프·메타가 모두 빈약하면 블로그 초안 시드를 확장 서술하되 새로운 사실은 만들지 않는다.',
  '- CTA는 온라인 쇼룸에서 더 비교해보는 흐름으로 마무리한다.',
].join('\n');

return [{
  json: {
    ...data,
    blogRequestBody: {
      model: data.blogModel,
      temperature: 0.7,
      max_tokens: 5600,
      response_format: { type: 'json_object' },
      messages: [
        {
          role: 'user',
          content: prompt,
        },
      ],
    },
  },
}];

const normalized = $('입력 정규화').first().json;
const response = $input.first().json ?? {};
const stripCodeFences = (value) => typeof value === 'string' ? value.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/i, '').trim() : '';
const rawContent = stripCodeFences(response.choices?.[0]?.message?.content ?? '');

let parsed;
try {
  parsed = JSON.parse(rawContent);
} catch (error) {
  parsed = {
    title: normalized.titleHint,
    summary: normalized.hook || '',
    body_markdown: normalized.blogDraftMarkdown || '',
    hashtags: ['#파인드가구', '#온라인쇼룸'],
    review_note: '응답 파싱 실패로 초안 원문을 fallback으로 사용했습니다.',
  };
}

return [{
  json: {
    ok: true,
    contentType: normalized.contentType,
    channel: 'blog',
    displayName: normalized.displayName,
    generatedAt: new Date().toISOString(),
    payload: {
      request: {
        displayName: normalized.displayName,
        siteName: normalized.siteName,
        externalLabel: normalized.externalLabel,
        industry: normalized.industry,
      },
      blog: parsed,
      raw: rawContent || null,
    },
  },
}];

const normalized = $('입력 정규화').first().json;
return [{
  json: {
    ok: false,
    contentType: normalized.contentType,
    channel: normalized.channel,
    error: 'unsupported_channel',
    message: 'channel must be either "cardnews" or "blog".',
    supportedChannels: ['cardnews', 'blog'],
  },
}];
